class Solution:
    def maximumSum(self, nums):
        groups = {0: [], 1: [], 2: []}
        for x in nums:
            groups[x % 3].append(x)
        for k in groups:
            groups[k].sort(reverse=True)
        best = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                s2 = nums[i] + nums[j]
                for m in range(j + 1, n):
                    s3 = s2 + nums[m]
                    if s3 % 3 == 0 and s3 > best:
                        best = s3
        return best

