        for k in groups:
            groups[k].sort(reverse=True)
        best = 0
        for r in (0, 1, 2):
            if len(groups[r]) >= 3:
                total = sum(groups[r][:3])
                if total > best:
                    best = total
        if groups[0] and groups[1] and groups[2]:
            total = groups[0][0] + groups[1][0] + groups[2][0]
            if total > best:
                best = total
        return best

