var maximumSum = function(nums) {
    const groups = { 0: [], 1: [], 2: [] };
    for (const x of nums) groups[x % 3].push(x);
    for (const k of [0, 1, 2]) groups[k].sort((a, b) => b - a);
    let best = 0;
    for (const r of [0, 1, 2]) {
        if (groups[r].length >= 3) {
            const total = groups[r][0] + groups[r][1] + groups[r][2];
            if (total > best) best = total;
        }
    }
    if (groups[0].length && groups[1].length && groups[2].length) {
        const total = groups[0][0] + groups[1][0] + groups[2][0];
        if (total > best) best = total;
    }
    return best;
};
